import fs from 'node:fs'
import path from 'node:path'

function requiredEnv(name) {
  const value = process.env[name]?.replace(/\\n/g, '\n').trim()
  if (!value) {
    throw new Error(`Missing required environment variable: ${name}`)
  }

  return value
}

function validatePublicKey(publicKey) {
  const lines = publicKey.split(/\r?\n/).filter((line) => line.trim())
  if (lines.length < 2 || !/comment/i.test(lines[0])) {
    throw new Error(
      'ROUTEX_UPDATER_PUBLIC_KEY must be the full public key file generated by `tauri signer generate`, including its comment line'
    )
  }
}

const outputPath = process.argv[2] || 'src-tauri/tauri.release.conf.json'
const publicKey = requiredEnv('ROUTEX_UPDATER_PUBLIC_KEY')
validatePublicKey(publicKey)

const releaseConfig = {
  bundle: {
    createUpdaterArtifacts: true
  },
  plugins: {
    updater: {
      pubkey: publicKey
    }
  }
}

fs.mkdirSync(path.dirname(outputPath), { recursive: true })
fs.writeFileSync(outputPath, `${JSON.stringify(releaseConfig, null, 2)}\n`)
console.log(`[release-config] wrote ${outputPath}`)
